import React, {useState} from 'react'
import userActions from "../redux/actions/userActions";
import Box from '@mui/material/Box'
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography'
import {Link as LinkRouter} from "react-router-dom"
import {connect} from 'react-redux'
import GoogleSignUp from '../components/GoogleSignUp';
import '../styles/signin-up.css'


function SignUp(props) {

    const [fullname,setFullname] = useState("")
    const [photo,setPhoto] = useState("")
    const [country,setCountry] = useState("")
    const [email,setEmail] = useState("")
    const [password,setPassword] = useState("")

    var countries = ["","Mexico","U.S.A.","Brazil","Argentina","China","Japan","Spain","England","France","Italy","Belgium"]

    const handleSubmit = (event) => {
        event.preventDefault()
        const userData = {
            fullname: fullname,
            photo: photo,
            email: email,
            password: password,
            country: country,
            from: "form-Signup"
        }
        props.signUpUser(userData)
    }

    return (
                    <div className='signin-upbody'>
                        <div className='form-container'>
                        <Typography variant="h2" className='festiveFont violetShadows' sx={{padding: '10px'}}>Register Now!</Typography>
                        <form onSubmit={handleSubmit} className='form'>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                    <TextField label="Full name" variant="filled" color="success" focused type='text' name='Fullname' id='Fullname' placeholder='Fullname' className='myInput' value={fullname} onChange={e=>setFullname(e.target.value)} required />
                            </Box>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                    <TextField label="Photo URL" variant="filled" color="success" focused type='text' name='userPhoto' id='userPhoto' placeholder="Photo URL" className='myInput' value={photo} onChange={e=>setPhoto(e.target.value)} required />
                            </Box>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                <select name="country" id="country" className='myInput' onChange={e=>setCountry(e.target.value)} required>
                                    {countries.map( everyCountry =>
                                    <option key={everyCountry} value={everyCountry}>{everyCountry}</option>)}
                                </select>
                            </Box>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                    <TextField label="Photo URL" variant="filled" color="success" focused type='email' name='email' id='email' placeholder='mail' className='myInput' value={email} onChange={e=>setEmail(e.target.value)} required />
                            </Box>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                    <TextField label="Photo URL" variant="filled" color="success" focused type='password' name='password' id='password' placeholder='password' className='myInput' value={password} onChange={e=>setPassword(e.target.value)} required/>
                            </Box>
                            <GoogleSignUp/>
                            <Box sx={{
                                display: 'flex',
                                height: '40px',
                                width: '40%',
                                minWidth: '280px',}}>
                                <input type="submit" value='SignUp!' className='myButton fredokaFont' required />
                                <LinkRouter to={'/signIn'} className='anchor festiveFont violetShadows'>You have account? go to SignIn!</LinkRouter>
                            </Box>
                        </form>
                        </div>
                    </div>
    )
}
const mapDispatchToProps = {
    signUpUser: userActions.signUpUser
}
const mapStateToProps = (state) => {
    return {
        message: state.userReducers.message
    }
}
export default connect(mapStateToProps, mapDispatchToProps)(SignUp)
